'use strict';

var inspect = require('../');
var test = require('tape');

test('quoteGT option', function (t) {
    t['throws'](function () { inspect(null, { quoteGT: false }); }, 'false is not a valid value');
    t['throws'](function () { inspect(null, { quoteGT: true }); }, 'true is not a valid value');
    t['throws'](function () { inspect(null, { quoteGT: '' }); }, '"" is not a valid value');
    t['throws'](function () { inspect(null, { quoteGT: {} }); }, '{} is not a valid value');
    t['throws'](function () { inspect(null, { quoteGT: [] }); }, '[] is not a valid value');
    t['throws'](function () { inspect(null, { quoteGT: 42 }); }, '42 is not a valid value');
    t['throws'](function () { inspect(null, { quoteGT: NaN }); }, 'NaN is not a valid value');
    t['throws'](function () { inspect(null, { quoteGT: function () {} }); }, 'a function is not a valid value');

    t.equal(inspect('"', { quoteGT: 'single' }), '\'"\'', 'double quote, quoteGT: "single"');
    t.equal(inspect('"', { quoteGT: 'double' }), '"\\""', 'double quote, quoteGT: "double"');

    t.equal(inspect('\'', { quoteGT: 'single' }), '\'\\\'\'', 'single quote, quoteGT: "single"');
    t.equal(inspect('\'', { quoteGT: 'double' }), '"\'"', 'single quote, quoteGT: "double"');

    t.equal(inspect('`', { quoteGT: 'single' }), '\'`\'', 'backtick, quoteGT: "single"');
    t.equal(inspect('`', { quoteGT: 'double' }), '"`"', 'backtick, quoteGT: "double"');

    t.end();
});
